#include<cstdio>
#include<algorithm>
#include<cmath>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
template<typename T> inline T max(const T&x,const T&y){return y<x?x:y;}
template<typename T> inline void chkmin(T&x,const T&w){w<x?x=w:T();}
const int N=4e5+10;double Mn=5e18;struct node{double x,y;}t[N];
inline double SQ(double k){return k*k;} double P,Q;
inline double Cnt(int i,int j){return SQ(t[i].x-t[j].x)+SQ(t[i].y-t[j].y);}
int main()
{
	double P=sin(1),Q=cos(1);
	int n=read();rep(1,n,i)
	{
		double x=read(),y=read();
		t[i].x=x*P-y*Q;t[i].y=x*Q+y*P;
	}
	std::sort(t+1,t+n+1,[&](const node&x,const node&y){return x.x*x.y<y.x*y.y;});
	rep(1,n,i){int q=max(1,i-75);for(int j=q;j<i;++j){chkmin(Mn,Cnt(i,j));}}
	printf("%.0lf\n",Mn);return 0;
}
